openscad:
dial_diameter = 40; // [20:1:80]
bezel_width = 4; // [1:0.5:10]
case_thickness = 6; // [3:0.5:12]
hand_length_h = 13; // [5:1:25]
hand_length_m = 17; // [5:1:30]
hand_width = 1.8; // [0.5:0.2:4]
marker_height = 2; // [1:0.5:5]
$fn = 60;
module watch() {
    color("yellow")
    cylinder(h=case_thickness, d=dial_diameter+bezel_width*2, center=true);
    color("white")
    translate([0,0,case_thickness/2+0.1])
    cylinder(h=1.5, d=dial_diameter, center=true);
    color("black")
    for (i=[0:11]) {
        rotate([0,0,i*30])
        translate([0,dial_diameter/2-5,case_thickness/2+1.6])
        cube([2.5,6,marker_height], center=true);
    }
    color("black")
    translate([0,0,case_thickness/2+2])
    rotate([0,0,50])
    linear_extrude(height=2)
    square([hand_width,hand_length_h], center=true);
    color("black")
    translate([0,0,case_thickness/2+2.5])
    rotate([0,0,110])
    linear_extrude(height=2)
    square([hand_width,hand_length_m], center=true);
    color("black")
    translate([0,0,case_thickness/2+3])
    cylinder(h=3, d=2, center=true);
}
watch();
